def {{nama_fungsi}}(caller_func, prompt_variants: dict, **caller_kwargs):
    """prompt_variants: dict {nama_varian: teks_prompt}. Kembalikan dict {nama_varian: hasil}."""
    results = {}
    for variant_name, prompt_text in prompt_variants.items():
        try:
            results[variant_name] = caller_func(prompt_text, **caller_kwargs)
        except Exception as e:
            results[variant_name] = f"ERROR: {e}"
    return results

def {{nama_fungsi}}(caller_func, inputs: list, **caller_kwargs):
    """Jalankan caller_func untuk tiap item di inputs. Hasil gagal ditandai None, tidak menghentikan batch."""
    results = []
    for idx, item in enumerate(inputs):
        try:
            output = caller_func(item, **caller_kwargs)
            results.append({"index": idx, "input": item, "output": output, "error": None})
        except Exception as e:
            results.append({"index": idx, "input": item, "output": None, "error": str(e)})
    return results
